import json, sys
sys.stdout.reconfigure(encoding='utf-8')

with open('C:/Users/laboratorio/Downloads/ROBO/CLAUDE HISTORICO CONVERSA/9cc8e558-cb85-4f49-8e2f-dfaae39f0be1.jsonl', 'r', encoding='utf-8') as f:
    lines = f.readlines()

# Get tool use calls to understand what code was changed
for i, line in enumerate(lines[800:930], start=801):
    try:
        obj = json.loads(line)
        msg_type = obj.get('type')
        if msg_type == 'assistant':
            msg = obj.get('message', {})
            content = msg.get('content', [])
            if isinstance(content, list):
                for c in content:
                    if c.get('type') == 'tool_use' and c.get('name') in ['Edit', 'Write', 'Bash']:
                        tool_name = c.get('name')
                        inp = c.get('input', {})
                        print(f'--- LINE {i} TOOL: {tool_name} ---')
                        if tool_name in ['Edit', 'Write']:
                            print(f'File: {inp.get(\"file_path\",\"\")}')
                            if 'old_string' in inp:
                                print(f'OLD: {str(inp.get(\"old_string\",\"\"))[:300]}')
                            print(f'NEW: {str(inp.get(\"new_string\", inp.get(\"content\",\"\")))[:400]}')
                        elif tool_name == 'Bash':
                            print(f'CMD: {str(inp.get(\"command\",\"\"))[:400]}')
                        print()
    except Exception as e:
        pass
